import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class AudioLevelIndicator extends StatelessWidget { final double level; const AudioLevelIndicator({super.key, required this.level}); @override Widget build(BuildContext context) { return Row(mainAxisSize: MainAxisSize.min, children: List.generate(5, (i) { final active = level >= (i + 1) / 5; return Container(width: 3, height: 6.0 + i * 3, margin: const EdgeInsets.only(right: 2), decoration: BoxDecoration(color: active ? AppTheme.successColor : AppTheme.darkBorder, borderRadius: BorderRadius.circular(2))); })); } }